            dy = 1
        elif my > center[1]:
            dy = -1
        # adjust to avoid obstacle or stay in bounds
        nx, ny = mx + dx, my + dy
        if not in_bounds(nx, ny) or (nx, ny) in obstacles:
            best_move = (0, 0)
        else:
            best_move = (dx, dy)

        return [best_move[0], best_move[1]]

    return [best_move[0], best_move[1]]
